/**
 * Generates a map where key is XOR sum and value is the maximum subset size achieving that XOR sum.
 * Uses Meet-in-the-Middle technique subset enumeration via bitmasks.
 * @param {number[]} arr The array segment.
 * @returns {Map<number, number>} Map of {xor_sum: max_size}
 */
function generateXorMap(arr) {
    // Map<XOR_Sum, Max_Size>
    const map = new Map();
    // Initialize with the empty set: XOR sum 0, size 0.
    map.set(0, 0);

    const n = arr.length;

    // Iterate through all 2^n non-empty subsets using bitmasks
    for (let i = 1; i < (1 << n); i++) {
        let currentXorSum = 0;
        let currentSize = 0;

        for (let j = 0; j < n; j++) {
            if ((i >> j) & 1) {
                currentXorSum ^= arr[j];
                currentSize++;
            }
        }

        const existingSize = map.get(currentXorSum) || -1;
        if (currentSize > existingSize) {
            map.set(currentXorSum, currentSize);
        }
    }

    return map;
}

function solve(nums, target) {
    const N = nums.length;
    if (N === 0) {
        return target === 0 ? 0 : -1;
    }

    // Split the array into two halves
    const N_A = Math.floor(N / 2);
    const A = nums.slice(0, N_A);
    const B = nums.slice(N_A);

    // 1. Generate maps for A and B
    // MapA[xorA] = max size of subset in A resulting in xorA
    const mapA = generateXorMap(A);
    // MapB[xorB] = max size of subset in B resulting in xorB
    const mapB = generateXorMap(B);

    // 2. Find the maximum total size (k_A + k_B) such that xorA ^ xorB = target
    let maxSize = -1;

    // Iterate through mapA entries
    for (const [xorA, sizeA] of mapA.entries()) {
        // We need xorB = target ^ xorA
        const xorB_needed = target ^ xorA;

        if (mapB.has(xorB_needed)) {
            const sizeB = mapB.get(xorB_needed);
            const totalSize = sizeA + sizeB;

            if (totalSize > maxSize) {
                maxSize = totalSize;
            }
        }
    }

    // 3. Determine minimum removals
    if (maxSize === -1) {
        // This case implies no combination (including empty sets) resulted in the target XOR sum.
        return -1;
    } else {
        // Minimum removals = Total elements - Maximum retained elements
        return N - maxSize;
    }
}
